async function e(e){let t=e.dataset.src;if(!t)return;let n=(await fetch(t).then(e=>e.json())).nodes??[];e.innerHTML=`<svg role="img" aria-label="Loop topology" viewBox="0 0 720 ${Math.max(160,n.length*70)}">${n.map((e,t)=>{let n=40+t*62,r=String(e.display_name??e.loop_id??e.id??`loop`),i=String(e.status??`unknown`);return`<g><rect x="20" y="${n-24}" width="260" height="44" rx="10" fill="#182850" stroke="#7cd4ff"/><text x="36" y="${n}" fill="#eef3ff">${r} · ${i}</text></g>`}).join(``)}</svg>`}async function t(e){let t=e.dataset.src;if(!t)return;let n=await fetch(t).then(e=>e.json());e.innerHTML=`<ol class="timeline">${(n.timeline??n.events??[]).slice(0,50).map(e=>`<li><strong>${String(e.event_type??e.item_type??`event`)}</strong> ${String(e.summary??``)}</li>`).join(``)}</ol>`}async function n(e){let t=e.dataset.src;if(!t)return;let n=await fetch(t).then(e=>e.json());e.innerHTML=`<p class="${String(n.verdict??``)}">Deterministic verdict: <strong>${String(n.verdict??`inconclusive`)}</strong></p>`}for(let r of document.querySelectorAll(`[id$="-island"]`))r.id.includes(`topology`)?e(r):r.id.includes(`impact`)?n(r):t(r);